import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Profile({ API_URL, user }) {
  const [profile, setProfile] = useState(null);
  const [newService, setNewService] = useState({ title: '', description: '', category: '', credits: 1 });
  const [categories, setCategories] = useState([]);

  useEffect(() => {
    if (user) {
      fetchProfile();
      fetchCategories();
    }
  }, [user]);

  const fetchProfile = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/user/profile`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProfile(response.data);
    } catch (err) {
      console.error('Error fetching profile:', err);
    }
  };

  const fetchCategories = async () => {
    try {
      const response = await axios.get(`${API_URL}/categories`);
      setCategories(response.data);
    } catch (err) {
      console.error('Error fetching categories:', err);
    }
  };

  const createService = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      await axios.post(`${API_URL}/services`, newService, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setNewService({ title: '', description: '', category: '', credits: 1 });
      fetchProfile();
      alert('Service added!');
    } catch (err) {
      alert(err.response?.data?.error || 'Failed to create service');
    }
  };

  if (!user) return <div className="container">Please login</div>;
  if (!profile) return <div className="container">Loading profile...</div>;

  return (
    <div>
      <div className="card">
        <h2>My Profile</h2>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <div>
            <h3>{profile.user.name}</h3>
            <p>{profile.user.email}</p>
            <p><strong>Skills:</strong> {profile.user.skills?.join(', ')}</p>
          </div>
          <div className="credit-badge" style={{ fontSize: '24px' }}>
            💰 {profile.user.credits} Credits
          </div>
        </div>
      </div>

      <div className="card">
        <h3>Add New Service</h3>
        <form onSubmit={createService}>
          <input
            type="text"
            placeholder="Service Title (e.g., 'Sewing - Pants Hemming')"
            className="input"
            value={newService.title}
            onChange={(e) => setNewService({...newService, title: e.target.value})}
            required
          />

          <textarea
            placeholder="Description"
            className="input"
            rows="3"
            value={newService.description}
            onChange={(e) => setNewService({...newService, description: e.target.value})}
          />

          <select
            className="input"
            value={newService.category}
            onChange={(e) => setNewService({...newService, category: e.target.value})}
            required
          >
            <option value="">Select Category</option>
            {categories.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>

          <input
            type="number"
            placeholder="Credits Required"
            className="input"
            min="1"
            max="10"
            value={newService.credits}
            onChange={(e) => setNewService({...newService, credits: parseInt(e.target.value)})}
          />

          <button type="submit" className="btn btn-primary">Add Service</button>
        </form>
      </div>

      <div className="card">
        <h3>My Services</h3>
        {profile.services?.length > 0 ? (
          profile.services.map(service => (
            <div key={service._id} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
              <strong>{service.title}</strong> - {service.credits} credits
              <br/>
              <span style={{ color: '#666' }}>{service.description}</span>
            </div>
          ))
        ) : (
          <p>No services added yet.</p>
        )}
      </div>
    </div>
  );
}

export default Profile;
